/**
 * @summary Generate a full PRD from a feature idea
 */
export const getGeneratePrdUrl = () => {
  return `/api/ai/generate-prd`;
};

export const generatePrd = async (
  generatePrdBody: GeneratePrdBody,
  options?: RequestInit,
): Promise<GeneratePrdResponse> => {
  return customFetch<GeneratePrdResponse>(getGeneratePrdUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(generatePrdBody),
  });
};

export const getGeneratePrdMutationOptions = <
  TError = ErrorType<void>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof generatePrd>>,
    TError,
    { data: BodyType<GeneratePrdBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof generatePrd>>,
  TError,
  { data: BodyType<GeneratePrdBody> },
  TContext
> => {
  const mutationKey = ["generatePrd"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof generatePrd>>,
    { data: BodyType<GeneratePrdBody> }
  > = (props) => {
    const { data } = props ?? {};

    return generatePrd(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type GeneratePrdMutationResult = NonNullable<
  Awaited<ReturnType<typeof generatePrd>>
>;
export type GeneratePrdMutationBody = BodyType<GeneratePrdBody>;
export type GeneratePrdMutationError = ErrorType<void>;

/**
 * @summary Generate a full PRD from a feature idea
 */
export const useGeneratePrd = <
  TError = ErrorType<void>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof generatePrd>>,
    TError,
    { data: BodyType<GeneratePrdBody> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof generatePrd>>,
  TError,
  { data: BodyType<GeneratePrdBody> },
  TContext
> => {
  return useMutation(getGeneratePrdMutationOptions(options));
};
